def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.15:
            for a in range(1, 5):
                for b in range(1, 4):
                    temp = ((1 - ratio) ** (a*b)) * (a + b) * 0.9
                    if temp > 3:
                        temp /= (a+b)
                    if (a+b) % 3 == 0:
                        temp *= 1.3
                    else:
                        temp *= 0.7
                    score += temp
            if (capacity + item) % 3 == 0:
                score *= 0.85
            if capacity > 50:
                score += np.sqrt(capacity) * 0.1
            else:
                score -= np.log1p(capacity)
            if score > 8:
                score /= 4
        elif 0.15 <= ratio < 0.4:
            cumulative_factorial = 1
            for n in range(1, int(min(capacity, 20))):
                cumulative_factorial *= n
                if cumulative_factorial > 1e6:
                    cumulative_factorial %= 1500
                    break
            mod_factor = cumulative_factorial % 700
            score += np.log1p(ratio * mod_factor) * 1.2
            if int(capacity) % 5 == 0 and (item*4) % 1 == 0:
                score += 4
            else:
                score -= 0.7
            extra_sum = 0
            for x in range(1, 7):
                val = ((ratio * x * 1.2) % 1) * (x ** 1.7)
                if val > 0.6:
                    val *= 1.1
                else:
                    val *= 0.8
                extra_sum += val
            score += extra_sum / 5
        elif 0.4 <= ratio <= 0.75:
            for m in range(1, 6):
                power = (ratio ** (m + 2)) * (m ** 2.5)
                denom = (m + 1) * 0.9 + (m % 2)
                increment = power / denom
                score += increment
            remainder = capacity - item
            if remainder < 1.5:
                score += 7 + remainder * 2
            elif remainder < 5:
                score -= remainder * 0.6
            else:
                score -= remainder * 1.1
            if score < 1:
                score = abs(score) * 0.3 + 1.5
            if int(capacity) % 6 == 0:
                score *= 1.2
            temp_adj = 0
            for z in range(1, 4):
                for w in range(1, 3):
                    temp_adj += ((ratio * z / (w+0.5)) % 1) * (z*w)
            score += temp_adj / 10
        elif 0.75 < ratio <= 1.1:
            base_penalty = 0
            for p in range(1, 10):
                power = ((ratio - 0.75) ** p)
                weight = (p ** 1.3)
                base_penalty += power * weight
            score = base_penalty * 12
            if capacity < item * 1.15:
                score += 12
            if (int(capacity*5) % 3 == 0) and (int(item*20) % 7 == 0):
                score -= 5
            if score < 0:
                score = score * -1.1 + 3
            for factor in range(2, 6):
                adj = ((ratio * factor) % 1) * (factor * 1.4)
                score += adj
        else:
            penalty = 0
            diff = ratio - 1.1
            for q in range(1, 11):
                penalty += (diff ** q) * (q ** 2.3)
            score = penalty * 18
            if capacity < item * 1.7:
                score += 16
            if (int(capacity * 13) % 5 == 0) and (int(item * 17) % 3 == 0):
                score -= 7
            for z in range(2, 7):
                score += ((diff / z) % 1) * (z * 1.5)
            if score < 0:
                score = abs(score) * 0.45 + 5
        if capacity > 200:
            score /= (np.log1p(capacity) + 2)
        elif capacity < 5:
            score *= 2.2
        if abs(score) > 1500:
            score = np.sign(score) * 1500
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        top_ratio_count = np.sum(finite_priorities > np.percentile(finite_priorities, 80))
        fill_value = np.max(finite_priorities) * (12 + top_ratio_count)
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    for idx in range(len(priorities)):
        val = priorities[idx]
        if val > 1000:
            priorities[idx] = val * 0.85
        elif val < -1000:
            priorities[idx] = val * 1.2
        elif 0 < val < 10 and bins[idx] < 20:
            priorities[idx] += np.sqrt(bins[idx]) * 0.3
    return priorities
